member.example:
Bind a single color channel of the Graphic color property using a serialized binder field — the target Graphic is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private GraphicColorComponentBinder _alpha;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _alpha;
    }


Bind a single color channel of the Graphic color property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Graphic _graphic;
        
        private GraphicColorComponentBinder Alpha =>
            new(_graphic, ColorComponent.A);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _alpha;
    }

Switch a single color channel of the Graphic color between two values using a serialized binder field — the target Graphic is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private GraphicColorComponentSwitcherBinder _isVisible;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }


Switch a single color channel of the Graphic color between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Graphic _graphic;
        
        private GraphicColorComponentSwitcherBinder IsVisible => new(
            _graphic, trueColor: 1f, falseColor: 0f, ColorComponent.A);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }
